import{c as t,Q as a,j as r,m as s}from"./chunks/framework.BXc4yaFE.js";const c=JSON.parse('{"title":"什么才是真正的 Harness Engineering？— @SaitoWu","description":"","frontmatter":{"title":"什么才是真正的 Harness Engineering？— @SaitoWu","author":"Saito（@SaitoWu）","date":"2026-04-18T00:00:00.000Z","source":"https://x.com/SaitoWu/status/2045458721929892345","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-04-18-@SaitoWu-892345.md","filePath":"research/tweets/2026-04-18-@SaitoWu-892345.md","lastUpdated":1779894392000}'),i={name:"research/tweets/2026-04-18-@SaitoWu-892345.md"};function n(o,e,l,d,g,p){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="什么才是真正的-harness-engineering-—-saitowu" tabindex="-1">什么才是真正的 Harness Engineering？— @SaitoWu <a class="header-anchor" href="#什么才是真正的-harness-engineering-—-saitowu" aria-label="Permalink to &quot;什么才是真正的 Harness Engineering？— @SaitoWu&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/SaitoWu/status/2045458721929892345" target="_blank" rel="noreferrer">https://x.com/SaitoWu/status/2045458721929892345</a><strong>作者</strong>：Saito（@SaitoWu） <strong>發布日期</strong>：2026-04-18 <strong>收錄日期</strong>：2026-04-26 <strong>類型</strong>：Twitter Article <strong>統計</strong>：707 likes · 141 retweets · 1,672 bookmarks · 247,232 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>刚刷完 OpenAI Ryan 在伦敦的演讲 + 访谈，干货直接爆棚。</p><p>他一句话把 Harness Engineering 的核心说穿了：代码已经免费了（code is free），实施不再是瓶颈，人类真正的价值是&quot;steering&quot;（指导）— 定义什么是好代码、注入 guardrails、让 agent 自己去执行。</p><p>以前我们自己敲键盘，现在 agent 写 99% 的代码，我们只管 orchestration（编排）。来，拆解他最硬核的几点观点</p><p><strong>代码免费，但上下文和 guardrails 永远稀缺</strong></p><p>Ryan 说：模型已经够强了，能像人类一样写完整代码。</p><p>真正稀缺的是人类时间、注意力和模型上下文窗口。</p><p>所以 Harness 的本质就是：把人类经验（taste、review 标准、非功能要求）全部写成文本（docs、skills、ADRs、logs），让 agent 随时能看到&quot;什么叫好代码&quot;。</p><p><strong>别再把 agent 关在小盒子里，要给它完整工具和权限</strong></p><p>传统做法是给 agent 预设好 scaffold（脚手架），限制它一步步走。</p><p>Ryan 的做法完全相反：让 agent 自己成为整个 box，给它 CLI、bash、observability stack、甚至自己 spin up 服务的能力。</p><p>这样 agent 就能像全栈工程师一样，从头到尾把活干完，人类只需偶尔 review。</p><p><strong>人类角色彻底升级：从 implementer 变成 orchestrator</strong></p><p>以前工程师是&quot;写代码的人&quot;，现在是&quot;staff engineer 带 5000 个 agent 的团队 leader&quot;。</p><p>你的工作不再是敲代码，而是：</p><ul><li>定义优先级和 success criteria</li><li>观察 agent 哪里反复出错</li><li>把这些错误转化成 durable guardrails（lints、tests、review agents）</li><li>不断把人类时间解放到更高杠杆的事上</li></ul><p><strong>Skills + progressive disclosure 是神器</strong></p><p>Ryan 超级推 skills：只把「名字 + 描述」塞进上下文（几十 tokens），需要时才加载完整内容。</p><p>这样既省 token，又让 agent 更聪明。</p><p>他团队只用 5-10 个核心 skills，但不断打磨，让 agent 像老员工一样懂团队 taste。</p><p><strong>Review 也要 agent 化，人类只看 post-merge</strong></p><p>PR 不再需要人类同步 review。</p><p>他们用 review agents 自动检查代码（看 docs、guardrails、QA plan）。</p><p>人类只在最终 merge 前抽样看，或者 post-merge 再 review。</p><p>这样 agent 能 24/7 并行工作，人类不用一直卡在 review 瓶颈。</p><p><strong>让代码库本身变得 agent-friendly</strong></p><ul><li>所有东西尽量相同（one way to do X）</li><li>构建时间压到 1 分钟内</li><li>文件结构清晰、package 隔离、observability 内置</li><li>用 tests 和 lints 做 source code verification（验证代码结构本身）</li></ul><p>这样 agent 无论看哪里，都能快速理解、少犯错。</p><p><strong>一句话总结 Ryan 的核心观点：</strong></p><p>Harness Engineering 不是让 agent 帮你写代码，而是让你彻底从执行层解放出来，只做 steering 和 orchestration。</p><p>代码免费了，prompt 和 guardrails 才是王道。</p><p>把团队的 taste、标准、历史经验全部写成文本喂给 agent，你就拥有了一支 24/7 永不疲倦、永远在进步的 5000 人工程团队。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：拆解 OpenAI Ryan 在倫敦演講的 Harness Engineering 核心觀點：代碼免費、人類轉型為 orchestrator、Skills + progressive disclosure 是節省 token 的核心機制、agent-friendly codebase 的六個設計原則。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ul><li>Harness Engineering 的本質：把人類的 taste、review 標準、非功能要求全部文字化（docs、skills、ADRs），讓 agent 能隨時查閱「什麼是好代碼」</li><li>打破「sandbox agent」的傳統做法：給 agent 完整工具和權限（CLI、bash、observability stack），讓它像全棧工程師一樣從頭到尾執行</li><li>Skills + progressive disclosure：只把名字+描述放入 context（幾十 tokens），需要時才載入全文——現有實踐的正式理論基礎</li><li>人類角色從 implementer 轉型為 orchestrator，工作是「定義成功標準 + 觀察錯誤模式 + 把錯誤轉化為 durable guardrails」</li><li>Review 也 agent 化——人類只做 post-merge 抽樣，不阻塞 24/7 並行執行</li></ul><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Skills progressive disclosure：metadata 幾十 tokens，按需載入全文</li><li>團隊規模隱喻：「staff engineer 帶 5000 個 agent 的團隊 leader」</li><li>核心 Skills 數量建議：5-10 個，持續打磨</li><li>Build time 目標：1 分鐘內</li><li>來源：OpenAI Ryan 倫敦演講 + 訪談</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ul><li>內容源自「Ryan 的演講」但未明確指出是哪位 Ryan 或演講連結，可驗證性偏低</li><li>「5000 人工程團隊」的比喻是行銷語言，實際效能依任務複雜度高度差異化</li><li>agent-friendly codebase 的 6 個原則是普遍 SRE 最佳實踐（清晰結構、快速 build），並非 AI 時代新發現</li></ul><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>8/10</td><td>Skills progressive disclosure、guardrails 文字化、review agent 化三個核心概念均可直接映射到本 workspace 的 <code>.claude/rules/skill-authoring.md</code> 和 <code>/deep-review</code> Skill 的強化方向</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>「把人類 taste 全部文字化」和「agent-friendly codebase 設計」的框架有清晰的原創架構，不只是重複已知</td></tr><tr><td>C. 證據品質 (20%)</td><td>5/10</td><td>引用 OpenAI Ryan 演講但缺乏具體連結，無量化數據；整理品質高但可驗證性低</td></tr><tr><td>D. 技術深度 (15%)</td><td>7/10</td><td>六個 agent-friendly codebase 設計原則有具體性，Skills progressive disclosure 機制有技術深度</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>Harness Engineering 框架不限於 Claude Code，適用於所有 AI 輔助開發工作流</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.10/10</strong></td><td>8×0.3 + 7×0.2 + 5×0.2 + 7×0.15 + 8×0.15</td></tr></tbody></table><p><strong>整合決策</strong>：Rule <strong>理由</strong>：「把人類 taste 和歷史錯誤全部文字化喂給 agent」的原則應補充到 <code>.claude/rules/skill-authoring.md</code> 的設計哲學 section，強化「為何要寫 Known Gotchas」的理論依據</p>',48)])])}const h=t(i,[["render",n]]);export{c as __pageData,h as default};
